import{_ as e,C as o,c as r,o as i,j as l,G as h,a8 as n,a as s}from"./chunks/framework.DMZhn_gK.js";const m=JSON.parse('{"title":"进制、权重与计算本质——整理笔记","description":"","frontmatter":{},"headers":[],"relativePath":"coa/NumeralSystem.md","filePath":"coa/NumeralSystem.md","lastUpdated":1773581551000}'),u={name:"coa/NumeralSystem.md"};function d(c,a,p,b,q,_){const t=o("ArticleMetadata");return i(),r("div",null,[a[0]||(a[0]=l("h1",{id:"进制、权重与计算本质——整理笔记",tabindex:"-1"},[s("进制、权重与计算本质——整理笔记 "),l("a",{class:"header-anchor",href:"#进制、权重与计算本质——整理笔记","aria-label":'Permalink to "进制、权重与计算本质——整理笔记"'},"​")],-1)),h(t),a[1]||(a[1]=n('<blockquote><p>本笔记整理了以下核心问题：</p><ol><li>为什么有些进制之间可以“快速直转”，有些不行</li><li>是否可能存在 3 进制计算机，为什么现实中采用 2 进制</li><li>从数学角度看，进制本身是否是“必要的”</li></ol></blockquote><hr><h2 id="一、进制与权重的本质" tabindex="-1">一、进制与权重的本质 <a class="header-anchor" href="#一、进制与权重的本质" aria-label="Permalink to &quot;一、进制与权重的本质&quot;">​</a></h2><h3 id="_1-什么是进制" tabindex="-1">1. 什么是进制 <a class="header-anchor" href="#_1-什么是进制" aria-label="Permalink to &quot;1. 什么是进制&quot;">​</a></h3><ul><li><strong>进制不是“数本身”，而是“数的表示方法”</strong></li><li>本质是：用有限的符号系统表示无限的数</li></ul><p>例如同一个数：</p><ul><li>5₁₀ = 101₂ = 12₃</li></ul><p>数不变，表示法变。</p><hr><h3 id="_2-权重展开公式-通用" tabindex="-1">2. 权重展开公式（通用） <a class="header-anchor" href="#_2-权重展开公式-通用" aria-label="Permalink to &quot;2. 权重展开公式（通用）&quot;">​</a></h3><p>任意进制数都可以写成：</p><p>[ \\sum_{i=0}^{n} d_i \\times b^i ]</p><ul><li>(b)：进制基数</li><li>(d_i)：第 i 位的数码</li></ul><blockquote><p>这个公式描述的是<strong>数值大小</strong>，与进制表示无关。</p></blockquote><hr><h2 id="二、为什么-8-进制可以直接转-2-进制" tabindex="-1">二、为什么 8 进制可以直接转 2 进制？ <a class="header-anchor" href="#二、为什么-8-进制可以直接转-2-进制" aria-label="Permalink to &quot;二、为什么 8 进制可以直接转 2 进制？&quot;">​</a></h2><h3 id="_1-核心原因-幂同构" tabindex="-1">1. 核心原因：幂同构 <a class="header-anchor" href="#_1-核心原因-幂同构" aria-label="Permalink to &quot;1. 核心原因：幂同构&quot;">​</a></h3><p>[ 8 = 2^3 ]</p><p>因此： [ 8^n = 2^{3n} ]</p><ul><li>八进制的每一位权重</li><li>正好对应 <strong>3 个二进制位的权重</strong></li></ul><hr><h3 id="_2-直接结果" tabindex="-1">2. 直接结果 <a class="header-anchor" href="#_2-直接结果" aria-label="Permalink to &quot;2. 直接结果&quot;">​</a></h3><ul><li>每一位八进制数 ↔ 固定 3 位二进制</li><li>不需要经过“数值中转”</li></ul><p>这不是技巧，而是：</p><blockquote><p><strong>权重结构天然对齐</strong></p></blockquote><hr><h2 id="三、为什么-9-进制不能像-8-进制那样转-2-进制" tabindex="-1">三、为什么 9 进制不能像 8 进制那样转 2 进制？ <a class="header-anchor" href="#三、为什么-9-进制不能像-8-进制那样转-2-进制" aria-label="Permalink to &quot;三、为什么 9 进制不能像 8 进制那样转 2 进制？&quot;">​</a></h2><h3 id="_1-权重结构不相容" tabindex="-1">1. 权重结构不相容 <a class="header-anchor" href="#_1-权重结构不相容" aria-label="Permalink to &quot;1. 权重结构不相容&quot;">​</a></h3><p>[ 9 = 3^2 ]</p><p>而二进制基于： [ 2^k ]</p><ul><li>3 与 2 没有共同的幂结构</li><li>不存在整数 k，使 (3^{2n} = 2^k)</li></ul><hr><h3 id="_2-结果" tabindex="-1">2. 结果 <a class="header-anchor" href="#_2-结果" aria-label="Permalink to &quot;2. 结果&quot;">​</a></h3><ul><li>9 进制 → 2 进制 <strong>不存在位级直映射</strong></li><li>必须先计算数值大小，再重新编码</li></ul><blockquote><p>因此：<strong>先转十进制不是“习惯问题”，而是结构必然</strong></p></blockquote><hr><h2 id="四、有没有可能用-3-进制计算机" tabindex="-1">四、有没有可能用 3 进制计算机？ <a class="header-anchor" href="#四、有没有可能用-3-进制计算机" aria-label="Permalink to &quot;四、有没有可能用 3 进制计算机？&quot;">​</a></h2><h3 id="_1-数学结论" tabindex="-1">1. 数学结论 <a class="header-anchor" href="#_1-数学结论" aria-label="Permalink to &quot;1. 数学结论&quot;">​</a></h3><ul><li>理论上，最优进制 ≈ (e \\approx 2.718)</li><li>最接近的整数进制是：<strong>3</strong></li></ul><blockquote><p>所以三进制在信息密度上是最优的整数进制。</p></blockquote><hr><h3 id="_2-平衡三进制-重点" tabindex="-1">2. 平衡三进制（重点） <a class="header-anchor" href="#_2-平衡三进制-重点" aria-label="Permalink to &quot;2. 平衡三进制（重点）&quot;">​</a></h3><p>不是 {0,1,2}，而是：</p><table tabindex="0"><thead><tr><th>符号</th><th>含义</th></tr></thead><tbody><tr><td>−</td><td>−1</td></tr><tr><td>0</td><td>0</td></tr><tr><td>+</td><td>+1</td></tr></tbody></table><p>优点：</p><ul><li>不需要负号</li><li>加减对称</li><li>表达更自然</li></ul><hr><h3 id="_3-历史事实" tabindex="-1">3. 历史事实 <a class="header-anchor" href="#_3-历史事实" aria-label="Permalink to &quot;3. 历史事实&quot;">​</a></h3><ul><li>1958 年，苏联制造过三进制计算机 <strong>Setun</strong></li><li>可稳定运行，功耗低</li></ul><blockquote><p>三进制计算机 <strong>不是不可能，而是未被延续</strong></p></blockquote><hr><h3 id="_4-为什么现实中不用-3-进制" tabindex="-1">4. 为什么现实中不用 3 进制？ <a class="header-anchor" href="#_4-为什么现实中不用-3-进制" aria-label="Permalink to &quot;4. 为什么现实中不用 3 进制？&quot;">​</a></h3><p><strong>工程原因</strong>：</p><ol><li>物理世界更稳定地提供二态（通 / 断）</li><li>三态抗噪声能力更差</li><li>硬件成本和复杂度更高</li><li>二进制已形成完整生态（路径依赖）</li></ol><p>结论：</p><blockquote><p><strong>2 进制不是最优的数学选择，而是最稳妥的工程选择</strong></p></blockquote><hr><h2 id="五、从数学角度看-进制是否-必要" tabindex="-1">五、从数学角度看：进制是否“必要”？ <a class="header-anchor" href="#五、从数学角度看-进制是否-必要" aria-label="Permalink to &quot;五、从数学角度看：进制是否“必要”？&quot;">​</a></h2><h3 id="_1-数学中的立场" tabindex="-1">1. 数学中的立场 <a class="header-anchor" href="#_1-数学中的立场" aria-label="Permalink to &quot;1. 数学中的立场&quot;">​</a></h3><ul><li>数是抽象对象</li><li>与进制无关</li></ul><p>例如在集合论中： [ 5 = {0,1,2,3,4} ]</p><hr><h3 id="_2-进制的数学角色" tabindex="-1">2. 进制的数学角色 <a class="header-anchor" href="#_2-进制的数学角色" aria-label="Permalink to &quot;2. 进制的数学角色&quot;">​</a></h3><blockquote><p><strong>进制是一种编码，而不是本体</strong></p></blockquote><p>等价于：</p><ul><li>ASCII / UTF-8</li><li>摩尔斯电码</li></ul><p>都是“表示系统”。</p><hr><h3 id="_3-是否存在-不用进制-的数学" tabindex="-1">3. 是否存在“不用进制”的数学？ <a class="header-anchor" href="#_3-是否存在-不用进制-的数学" aria-label="Permalink to &quot;3. 是否存在“不用进制”的数学？&quot;">​</a></h3><p>存在：</p><ul><li>Peano 公理</li><li>λ 演算</li><li>一元编码（Unary）</li></ul><p>但：</p><ul><li>表达效率极低</li><li>不适合计算与工程</li></ul><hr><h2 id="六、统一理解-重要总结" tabindex="-1">六、统一理解（重要总结） <a class="header-anchor" href="#六、统一理解-重要总结" aria-label="Permalink to &quot;六、统一理解（重要总结）&quot;">​</a></h2><ul><li>数学关注：<strong>不变性、本体</strong></li><li>工程关注：<strong>效率、稳定、实现</strong></li></ul><blockquote><p><strong>进制不是数学必需的，但是计算必需的</strong></p></blockquote><hr><h2 id="七、一句话压轴总结" tabindex="-1">七、一句话压轴总结 <a class="header-anchor" href="#七、一句话压轴总结" aria-label="Permalink to &quot;七、一句话压轴总结&quot;">​</a></h2><blockquote><p><strong>进制不是数的本体，而是数的接口</strong><strong>2 进制统治计算机世界，不是因为完美，而是因为可靠</strong></p></blockquote><hr><p>（完）</p>',82))])}const g=e(u,[["render",d]]);export{m as __pageData,g as default};
